    // ════════════════════════════════════════════════════════════════════

    [Theory]
    [InlineData(".png", true)]
    [InlineData(".PNG", true)]
    [InlineData(".jpg", true)]
    [InlineData(".JPG", true)]
    [InlineData(".jpeg", true)]
    [InlineData(".JPEG", true)]
    [InlineData(".gif", true)]
    [InlineData(".GIF", true)]
    [InlineData(".bmp", true)]
    [InlineData(".BMP", true)]
    [InlineData(".webp", true)]
    [InlineData(".WEBP", true)]
    [InlineData(".txt", false)]
    [InlineData(".md", false)]
    [InlineData(".pdf", false)]
    [InlineData(".cs", false)]
    [InlineData(".json", false)]
    [InlineData("", false)]
    public void Convert_ReturnsExpected(string extension, bool expected)
    {
        var path = extension.Length > 0
            ? $"/tmp/test{extension}"
            : string.Empty;

        var result = IsImageExtensionConverter.Instance.Convert(
            path, typeof(bool), null, CultureInfo.InvariantCulture);

        Assert.Equal(expected, result);
    }

    [Fact]
    public void IsImageExtension_NullPath_ReturnsFalse()
    {
        var result = IsImageExtensionConverter.Instance.Convert(
            null, typeof(bool), null, CultureInfo.InvariantCulture);
        Assert.Equal(false, result);
    }

    [Fact]
    public void IsImageExtension_Instance_IsSingleton()
    {
        var a = IsImageExtensionConverter.Instance;
        var b = IsImageExtensionConverter.Instance;
        Assert.Same(a, b);
    }

    [Fact]
    public void IsImageExtension_ConvertBack_ReturnsValueUnchanged()
    {
        var result = IsImageExtensionConverter.Instance.ConvertBack(
            true, typeof(bool), null, CultureInfo.InvariantCulture);
        Assert.Equal(true, result);
    }

    [Fact]
    public void IsImageExtension_ConvertBack_Null_ReturnsNull()
    {
        var result = IsImageExtensionConverter.Instance.ConvertBack(
            null, typeof(bool), null, CultureInfo.InvariantCulture);
        Assert.Null(result);
    }

    // ════════════════════════════════════════════════════════════════════
    // FractionConverter
    // ════════════════════════════════════════════════════════════════════

    [Theory]
    [InlineData(100.0, "0.5", 50.0)]
    [InlineData(200.0, "0.75", 150.0)]
    [InlineData(400.0, "0.25", 100.0)]
    [InlineData(0.0, "0.75", 0.0)]
    [InlineData(100.0, "1.0", 100.0)]
    public void Convert_MultipliesByParameter(double value, string parameter, double expected)
    {
        var result = FractionConverter.Instance.Convert(
            value, typeof(double), parameter, CultureInfo.InvariantCulture);

        Assert.IsType<double>(result);
        Assert.Equal(expected, (double)result!, 9);
    }

    [Fact]
    public void Convert_NoParameter_DefaultsToPoint75()
    {
        var result = FractionConverter.Instance.Convert(
            200.0, typeof(double), null, CultureInfo.InvariantCulture);

        Assert.IsType<double>(result);
        Assert.Equal(150.0, (double)result!, 9); // 200 * 0.75 = 150
    }

    [Fact]
    public void Convert_NullValue_ReturnsNull()
    {
        var result = FractionConverter.Instance.Convert(
            null, typeof(double), "0.5", CultureInfo.InvariantCulture);
        Assert.Null(result);
    }

    [Fact]
    public void Convert_NonDoubleValue_ReturnsNull()
    {
        var result = FractionConverter.Instance.Convert(
            "not-a-number", typeof(double), "0.5", CultureInfo.InvariantCulture);
        Assert.Null(result);
    }

    [Fact]
    public void Convert_NonNumericParameter_DefaultsToPoint75()
    {
        var result = FractionConverter.Instance.Convert(
            200.0, typeof(double), "not-a-number", CultureInfo.InvariantCulture);

        Assert.IsType<double>(result);
        Assert.Equal(150.0, (double)result!, 9); // falls back to 0.75
    }

    [Fact]
    public void Fraction_Instance_IsSingleton()
    {
        var a = FractionConverter.Instance;
        var b = FractionConverter.Instance;
        Assert.Same(a, b);
    }

    [Fact]
    public void Fraction_ConvertBack_ReturnsValueUnchanged()
    {
        var result = FractionConverter.Instance.ConvertBack(
            42.0, typeof(double), null, CultureInfo.InvariantCulture);
        Assert.Equal(42.0, result);
    }

    [Fact]
    public void Fraction_ConvertBack_Null_ReturnsNull()
    {
        var result = FractionConverter.Instance.ConvertBack(
            null, typeof(double), null, CultureInfo.InvariantCulture);
        Assert.Null(result);
    }
}

using Avalonia;
using Avalonia.Controls;
using Avalonia.Media.Imaging;
using Avalonia.Threading;
using Avalonia.VisualTree;
using VisualRelay.App.ViewModels;
using VisualRelay.App.Views;
using VisualRelay.App.Views.Controls;

namespace VisualRelay.Tests;

/// <summary>
/// Integration tests that verify inline image display in the Attachments tab.
///
/// When an attachment is an image (.png, .jpg, .jpeg, .gif, .bmp, .webp),
/// an <see cref="Image"/> element must render above the Reveal/Remove buttons
/// and file-path text. Non-image attachments must NOT render any Image element.
/// Both Reveal and Remove buttons must still be present for image attachments.
/// </summary>
[Collection("Headless")]
public sealed class AttachmentImageDisplayTests
{
    // Minimal 1×1 red PNG (valid, decodable).
    private static readonly byte[] MinimalPngBytes = Convert.FromBase64String(
        "iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==");

    /// <summary>
    /// When the selected task has a .png sibling, the Attachments tab must render
    /// an Image element with a non-null Source. This is the primary functional
    /// assertion for inline image display.
    /// </summary>
    [AvaloniaFact]
    public async Task ImageAttachment_RendersImageElement()
    {
        // ── Arrange: task with a .png attachment ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        var pngBytes = MinimalPngBytes;
        repo.WriteNestedTask("img-task", "# Image Task\n", ("screenshot.png", pngBytes));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "img-task");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: find the TaskDetailPanel, then search for Image elements ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Image? foundImage = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            // The Image element is inside the ItemsControl's DataTemplate.
            var img = sv.GetVisualDescendants()
                .OfType<Image>()
                .FirstOrDefault();
            if (img is not null)
            {
                foundImage = img;
                break;
            }
        }

        // ── Assert: an Image element must exist with a non-null Source ──
        Assert.NotNull(foundImage);
        Assert.NotNull(foundImage!.Source);
    }

    /// <summary>
    /// A non-image attachment (.txt) must NOT render any Image element inside
    /// the item template. This ensures the Image is only shown for recognized
    /// image extensions.
    /// </summary>
    [AvaloniaFact]
    public async Task NonImageAttachment_DoesNotRenderImageElement()
    {
        // ── Arrange: task with a .txt attachment ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        repo.WriteNestedTask("txt-task", "# Text Task\n", ("notes.txt", "hello"));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "txt-task");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: find the TaskDetailPanel, then search for Image elements ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Image? foundImage = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var img = sv.GetVisualDescendants()
                .OfType<Image>()
                .FirstOrDefault();
            if (img is not null)
            {
                foundImage = img;
                break;
            }
        }

        // ── Assert: no Image element for a non-image attachment ──
        Assert.Null(foundImage);
    }

    /// <summary>
    /// Image attachments must still expose Reveal and Remove buttons.
    /// The inline image preview is additive — it does not replace the
    /// existing action buttons.
    /// </summary>
    [AvaloniaFact]
    public async Task ImageAttachment_HasRevealAndRemoveButtons()
    {
        // ── Arrange: task with a .png attachment ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        repo.WriteNestedTask("img-task", "# Image Task\n", ("screenshot.png", MinimalPngBytes));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "img-task");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: locate Reveal and Remove buttons in the Attachments scroll area ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Button? revealButton = null;
        Button? removeButton = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var buttons = sv.GetVisualDescendants().OfType<Button>().ToList();
            revealButton = buttons.FirstOrDefault(b => b.Content?.ToString() == "Reveal");
            removeButton = buttons.FirstOrDefault(b => b.Content?.ToString() == "Remove");
            if (revealButton is not null && removeButton is not null)
                break;
        }

        // ── Assert: both buttons must be present ──
        Assert.NotNull(revealButton);
        Assert.NotNull(removeButton);
    }

    /// <summary>
    /// The Image element must have a MaxWidth constraint set — this
    /// implements the 50–75% panel-width sizing requirement.
    /// </summary>
    [AvaloniaFact]
    public async Task ImageAttachment_ImageHasMaxWidthConstraint()
    {
        // ── Arrange: task with a .png attachment ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        repo.WriteNestedTask("img-task", "# Image Task\n", ("screenshot.png", MinimalPngBytes));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "img-task");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: find the Image element ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Image? foundImage = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var img = sv.GetVisualDescendants()
                .OfType<Image>()
                .FirstOrDefault();
            if (img is not null)
            {
                foundImage = img;
                break;
            }
        }

        // ── Assert: Image exists and has a MaxWidth set ──
        Assert.NotNull(foundImage);
        // MaxWidth should not be default (double.PositiveInfinity) — it must be
        // constrained to a fraction of the parent width.
        Assert.True(
            foundImage!.MaxWidth < double.PositiveInfinity,
            $"Image MaxWidth is {foundImage.MaxWidth}, " +
            "must be a finite value (bound to a fraction of panel width).");
    }

    /// <summary>
    /// The Image element must have Stretch set to Uniform so the aspect
    /// ratio is preserved when scaling.
    /// </summary>
    [AvaloniaFact]
    public async Task ImageAttachment_ImageHasUniformStretch()
    {
        // ── Arrange ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        repo.WriteNestedTask("img-task", "# Image Task\n", ("screenshot.png", MinimalPngBytes));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "img-task");
        viewModel.SelectedTabIndex = 2;
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Image? foundImage = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var img = sv.GetVisualDescendants()
                .OfType<Image>()
                .FirstOrDefault();
            if (img is not null)
            {
                foundImage = img;
                break;
            }
        }

        Assert.NotNull(foundImage);
        Assert.Equal(Avalonia.Media.Stretch.Uniform, foundImage!.Stretch);
    }

    /// <summary>
    /// The Image element must have StretchDirection set to DownOnly so
    /// small images are not upscaled beyond their native resolution.
    /// </summary>
    [AvaloniaFact]
    public async Task ImageAttachment_ImageHasDownOnlyStretchDirection()
    {
        // ── Arrange ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        repo.WriteNestedTask("img-task", "# Image Task\n", ("screenshot.png", MinimalPngBytes));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "img-task");
        viewModel.SelectedTabIndex = 2;
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        Image? foundImage = null;
        foreach (var sv in taskDetailPanel.GetVisualDescendants().OfType<ScrollViewer>())
        {
            var img = sv.GetVisualDescendants()
                .OfType<Image>()
                .FirstOrDefault();
            if (img is not null)
            {
                foundImage = img;
                break;
            }
        }

        Assert.NotNull(foundImage);
        Assert.Equal(Avalonia.Media.StretchDirection.DownOnly, foundImage!.StretchDirection);
    }
}

